    const setups = data.tradingSetups.map(s => ({
      id: s.id, user_id: user.id, name: s.name, description: s.description, rules: s.rules
    }));
    const { error } = await supabase.from('journal_setups').upsert(setups, { onConflict: 'id' });
    if (error) console.error('Setups error:', error);
    else console.log('Setups done!');
